module counter8bit_up_sync (
    input clk,
    input rst,
    input en,
    output [7:0] q
);

    reg [7:0] count_reg;

    always @(posedge clk) begin
        if (rst)
            count_reg <= 8'b00000000;
        else if (en)
            count_reg <= count_reg + 1;
    end

    assign q = count_reg;

endmodule
